if (! function_exists('data_polynomial_fit')) {
    function data_polynomial_fit($x, $y, $degree = null, $predict_x = null)
    {
        if (!is_array($x) || !is_array($y) || count($x) !== count($y) || count($x) < 2) {
            return json_encode(['error' => 'x and y must be arrays of equal length with at least 2 points']);
        }
        $n = count($x);
        $deg = isset($degree) ? min(6, max(1, (int)$degree)) : 2;

        if ($n <= $deg) {
            return json_encode(['error' => "Need at least " . ($deg + 1) . " points for degree $deg polynomial (got $n)"]);
        }

        // Build the Vandermonde matrix: X[i][j] = x[i]^j for j=0..deg
        // Then solve (X^T * X) * coeffs = X^T * y using Gaussian elimination

        // Step 1: Build normal equations matrix A = X^T * X and vector b = X^T * y
        // A[j][k] = sum(x[i]^(j+k)) for j,k = 0..deg
        // b[j] = sum(y[i] * x[i]^j)

        $powers = []; // powers[i][j] = x[i]^j
        for ($i = 0; $i < $n; $i++) {
            $row = [1.0];
            for ($j = 1; $j <= $deg; $j++) {
                $row[] = $row[$j-1] * $x[$i];
            }
            $powers[] = $row;
        }

        // Build A and b
        $a = array_fill(0, $deg + 1, array_fill(0, $deg + 1, 0.0));
        $b = array_fill(0, $deg + 1, 0.0);

        for ($j = 0; $j <= $deg; $j++) {
            for ($k = 0; $k <= $deg; $k++) {
                $sum = 0.0;
                for ($i = 0; $i < $n; $i++) {
                    $sum += $powers[$i][$j] * $powers[$i][$k];
                }
                $a[$j][$k] = $sum;
            }
            $sumB = 0.0;
            for ($i = 0; $i < $n; $i++) {
                $sumB += $y[$i] * $powers[$i][$j];
            }
            $b[$j] = $sumB;
        }

        // Solve A * coeffs = b using Gaussian elimination with partial pivoting
        $m = $deg + 1;
        $coeffs = array_fill(0, $m, 0.0);

        // Augmented matrix
        $aug = [];
        for ($i = 0; $i < $m; $i++) {
            $aug[] = array_merge($a[$i], [$b[$i]]);
        }

        // Forward elimination
        for ($col = 0; $col < $m; $col++) {
            // Partial pivoting
            $maxVal = abs($aug[$col][$col]);
            $maxRow = $col;
            for ($row = $col + 1; $row < $m; $row++) {
                if (abs($aug[$row][$col]) > $maxVal) {
                    $maxVal = abs($aug[$row][$col]);
                    $maxRow = $row;
                }
            }
            if ($maxRow !== $col) {
                $temp = $aug[$col];
                $aug[$col] = $aug[$maxRow];
                $aug[$maxRow] = $temp;
            }

            // Check for singular matrix
            if (abs($aug[$col][$col]) < 1e-12) {
                return json_encode(['error' => 'Singular matrix - data may be degenerate or collinear']);
            }

            // Eliminate below
            for ($row = $col + 1; $row < $m; $row++) {
                $factor = $aug[$row][$col] / $aug[$col][$col];
                for ($j = $col; $j <= $m; $j++) {
                    $aug[$row][$j] -= $factor * $aug[$col][$j];
                }
            }
        }

        // Back substitution
        for ($row = $m - 1; $row >= 0; $row--) {
            $sum = $aug[$row][$m];
            for ($j = $row + 1; $j < $m; $j++) {
                $sum -= $aug[$row][$j] * $coeffs[$j];
            }
            $coeffs[$row] = $sum / $aug[$row][$row];
        }

        // Evaluate polynomial at given x value
        $polyVal = function($xVal, $coeffs) {
            $result = 0.0;
            $power = 1.0;
            foreach ($coeffs as $c) {
                $result += $c * $power;
                $power *= $xVal;
            }
            return $result;
        };

        // Compute fitted values, residuals, and R-squared
        $fitted = [];
        $residuals = [];
        $yMean = array_sum($y) / $n;
        $ssTot = 0.0;
        $ssRes = 0.0;

        for ($i = 0; $i < $n; $i++) {
            $pred = $polyVal($x[$i], $coeffs);
            $fitted[] = round($pred, 8);
            $res = $y[$i] - $pred;
            $residuals[] = round($res, 8);
            $ssTot += ($y[$i] - $yMean) * ($y[$i] - $yMean);
            $ssRes += $res * $res;
        }

        $rSquared = $ssTot > 1e-12 ? 1.0 - ($ssRes / $ssTot) : 0.0;
        $adjRSquared = 1.0 - (1.0 - $rSquared) * ($n - 1) / max(1, $n - $deg - 1);

        // Build equation string
        $eqParts = [];
        for ($j = 0; $j <= $deg; $j++) {
            $c = $coeffs[$j];
            if (abs($c) < 1e-12) continue;
            $sign = $c >= 0 ? ($j > 0 ? ' + ' : '') : ' - ';
            $absC = abs($c);
            if ($j === 0) {
                $eqParts[] = sprintf('%.6g', $c);
            } elseif ($j === 1) {
                $eqParts[] = $sign . (abs($absC - 1.0) < 1e-10 ? '' : sprintf('%.6g', $absC)) . 'x';
            } else {
                $eqParts[] = $sign . (abs($absC - 1.0) < 1e-10 ? '' : sprintf('%.6g', $absC)) . 'x^' . $j;
            }
        }
        $equation = 'y = ' . implode('', $eqParts);

        // Predictions
        $predictions = [];
        if (!empty($predict_x)) {
            foreach ($predict_x as $px) {
                $predictions[] = ['x' => $px, 'y_predicted' => round($polyVal($px, $coeffs), 8)];
            }
        }

        $coeffsOut = [];
        for ($j = 0; $j <= $deg; $j++) {
            $coeffsOut['c' . $j . ' (x^' . $j . ')'] = round($coeffs[$j], 8);
        }

        return json_encode([
            'n' => $n,
            'degree' => $deg,
            'coefficients' => $coeffsOut,
            'equation' => $equation,
            'r_squared' => round($rSquared, 8),
            'adjusted_r_squared' => round($adjRSquared, 8),
            'rmse' => round(sqrt($ssRes / $n), 8),
            'fitted_values' => $fitted,
            'residuals' => $residuals,
            'predictions' => $predictions,
            'next_steps' => [
                "Pass => 'fitted_values' to data_heatmap or data_to_emoji_art for visualization.",
                "Compare polynomial fits of different degrees to find the best model.",
                "Feed residuals to data_normalizer then data_histogram to check normality."
            ],
        ]);
    }
